import React, { useEffect, useState } from 'react';
import './ReviewProduct.scss';
import Lightbox from 'react-image-lightbox';
import 'react-image-lightbox/style.css';
import CommonUtils from '../../utils/CommonUtils';
import {
    createNewReviewService,
    getAllReviewByProductIdService,
    ReplyReviewService,
    deleteReviewService,
    checkUserBoughtProductService  // thêm service mới
} from '../../services/userService';
import { useParams } from 'react-router';
import { toast } from 'react-toastify';
import ReviewModal from './ReviewModal';

function ReviewProduct(props) {
    const { id } = useParams();
    const [inputValues, setInputValues] = useState({
        activeStar: '',
        imageReview: '',
        image: '',
        content: '',
        user: JSON.parse(localStorage.getItem('userData')),
        dataReview: [],
        countStar: {},
        isOpen: false,
        isOpenModal: false,
        parentId: ''
    });

    // State riêng để tránh closure bug
    const [hasBought, setHasBought] = useState(false);
    const [alreadyReviewed, setAlreadyReviewed] = useState(false);
    const [checkingBought, setCheckingBought] = useState(true);

    const user = JSON.parse(localStorage.getItem('userData'));

    useEffect(() => {
        let fetchData = async () => {
            await loadAllReview();
        };
        fetchData();
    }, []);

    // Chạy kiểm tra sau khi dataReview đã load
    useEffect(() => {
        if (user && inputValues.dataReview) {
            checkBoughtStatus();
        } else {
            setCheckingBought(false);
        }
    }, [inputValues.dataReview]);

    let checkBoughtStatus = async () => {
        try {
            setCheckingBought(true);

            // Kiểm tra đã mua chưa
            let res = await checkUserBoughtProductService(user.id, id);
            setHasBought(res && res.errCode === 0);

            // Kiểm tra đã đánh giá chưa (review gốc, không phải reply)
            let reviewed = inputValues.dataReview.some(
                item => item.userId === user.id && !item.parentId
            );
            setAlreadyReviewed(reviewed);
        } catch (error) {
            console.error('Lỗi kiểm tra trạng thái mua hàng:', error);
        } finally {
            setCheckingBought(false);
        }
    };

    let openPreviewImage = (url) => {
        setInputValues({ ...inputValues, imageReview: url, isOpen: true });
    };

    let loadAllReview = async () => {
        let res = await getAllReviewByProductIdService(id);
        if (res && res.errCode === 0) {
            let count5 = res.data.filter(item => item.star === 5);
            let count4 = res.data.filter(item => item.star === 4);
            let count3 = res.data.filter(item => item.star === 3);
            let count2 = res.data.filter(item => item.star === 2);
            let count1 = res.data.filter(item => item.star === 1);

            setInputValues(prev => ({
                ...prev,
                dataReview: res.data,
                countStar: {
                    star5: count5.length,
                    star4: count4.length,
                    star3: count3.length,
                    star2: count2.length,
                    star1: count1.length,
                    average: ((count5.length * 5) + (count4.length * 4) + (count3.length * 3) + (count2.length * 2) + (count1.length * 1))
                        / (count5.length + count4.length + count3.length + count2.length + count1.length),
                    quantity: count5.length + count4.length + count3.length + count2.length + count1.length
                },
                content: '',
                image: '',
                imageReview: '',
                activeStar: '',
                isOpenModal: false
            }));
        }
    };

    let handleChooseStart = (number) => {
        setInputValues({ ...inputValues, activeStar: number });
    };

    let handleOnChangeImage = async (event) => {
        let data = event.target.files;
        let file = data[0];
        if (file.size > 31312281) {
            toast.error('Dung lượng file bé hơn 30mb');
        } else {
            let base64 = await CommonUtils.getBase64(file);
            let objectUrl = URL.createObjectURL(file);
            setInputValues({ ...inputValues, image: base64, imageReview: objectUrl });
        }
    };

    const handleOnChange = event => {
        const { name, value } = event.target;
        setInputValues({ ...inputValues, [name]: value });
    };

    let handleSaveComment = async () => {
        if (!inputValues.activeStar) {
            toast.error('Bạn chưa chọn sao !');
            return;
        }
        if (!inputValues.content) {
            toast.error('Nội dung không được để trống !');
            return;
        }

        let response = await createNewReviewService({
            productId: id,
            content: inputValues.content,
            image: inputValues.image,
            userId: user.id,
            star: inputValues.activeStar
        });

        if (response && response.errCode === 0) {
            toast.success('Đăng đánh giá thành công !');
            setAlreadyReviewed(true);
            await loadAllReview();
        } else {
            toast.error(response.errMessage);
        }
    };

    let closeModal = () => {
        setInputValues({ ...inputValues, isOpenModal: false, parentId: '' });
    };

    let handleOpenModal = (id) => {
        setInputValues({ ...inputValues, isOpenModal: true, parentId: id });
    };

    let sendDataFromReViewModal = async (content) => {
        let res = await ReplyReviewService({
            content: content,
            productId: id,
            userId: user.id,
            parentId: inputValues.parentId
        });
        if (res && res.errCode === 0) {
            toast.success('Phản hồi thành công !');
            await loadAllReview();
        }
    };

    let handleDeleteReply = async (id) => {
        let res = await deleteReviewService({ data: { id: id } });
        if (res && res.errCode === 0) {
            toast.success('Xóa phản hồi thành công !');
            await loadAllReview();
        } else {
            toast.error(res.errMessage);
        }
    };

    // Render thông báo trạng thái form đánh giá
    let renderReviewForm = () => {
        // Chưa đăng nhập
        if (!user) {
            return (
                <div className="review_item">
                    <div className="alert-review alert-review--info">
                        <i className="fas fa-lock"></i>
                        <span>Vui lòng <a href="/login">đăng nhập</a> để đánh giá sản phẩm.</span>
                    </div>
                </div>
            );
        }

        // Đang kiểm tra
        if (checkingBought) {
            return (
                <div className="review_item">
                    <div className="alert-review alert-review--loading">
                        <i className="fas fa-spinner fa-spin"></i>
                        <span>Đang kiểm tra quyền đánh giá...</span>
                    </div>
                </div>
            );
        }

        // Đã đăng nhập nhưng chưa mua
        if (!hasBought) {
            return (
                <div className="review_item">
                    <div className="alert-review alert-review--warning">
                        <i className="fas fa-shopping-bag"></i>
                        <span>Bạn cần <strong>mua và nhận sản phẩm</strong> này trước khi có thể đánh giá.</span>
                    </div>
                </div>
            );
        }

        // Đã mua và đã đánh giá rồi
        if (alreadyReviewed) {
            return (
                <div className="review_item">
                    <div className="alert-review alert-review--success">
                        <i className="fas fa-check-circle"></i>
                        <span>Bạn đã đánh giá sản phẩm này rồi. Cảm ơn bạn!</span>
                    </div>
                </div>
            );
        }

        // Đã mua, chưa đánh giá → hiện form
        return (
            <div className="review_item">
                <div className="form-group">
                    <label style={{ color: '#333', fontSize: '16px', fontWeight: '600' }}>
                        Viết đánh giá của bạn
                    </label>
                    <textarea
                        name="content"
                        value={inputValues.content}
                        onChange={(event) => handleOnChange(event)}
                        rows="3"
                        className="form-control"
                        placeholder="Chia sẻ cảm nhận của bạn về sản phẩm..."
                    ></textarea>
                </div>
                <div className="content-review">
                    <div className="content-left">
                        <label style={{ marginBottom: '0', cursor: 'pointer' }} htmlFor="cmtImg">
                            <i className="fas fa-camera"></i>
                        </label>
                        <input
                            type="file"
                            id="cmtImg"
                            accept=".jpg,.png"
                            hidden
                            onChange={(event) => handleOnChangeImage(event)}
                        />
                        <div
                            className={inputValues.activeStar === 1 ? 'box-star active' : 'box-star'}
                            onClick={() => handleChooseStart(1)}
                        >
                            <i className="fa fa-star" />
                        </div>
                        <div
                            className={inputValues.activeStar === 2 ? 'box-star active' : 'box-star'}
                            onClick={() => handleChooseStart(2)}
                        >
                            <i className="fa fa-star" /><i className="fa fa-star" />
                        </div>
                        <div
                            className={inputValues.activeStar === 3 ? 'box-star active' : 'box-star'}
                            onClick={() => handleChooseStart(3)}
                        >
                            <i className="fa fa-star" /><i className="fa fa-star" /><i className="fa fa-star" />
                        </div>
                        <div
                            className={inputValues.activeStar === 4 ? 'box-star active' : 'box-star'}
                            onClick={() => handleChooseStart(4)}
                        >
                            <i className="fa fa-star" /><i className="fa fa-star" /><i className="fa fa-star" /><i className="fa fa-star" />
                        </div>
                        <div
                            className={inputValues.activeStar === 5 ? 'box-star active' : 'box-star'}
                            onClick={() => handleChooseStart(5)}
                        >
                            <i className="fa fa-star" /><i className="fa fa-star" /><i className="fa fa-star" /><i className="fa fa-star" /><i className="fa fa-star" />
                        </div>
                    </div>
                    <div className="content-right">
                        <button onClick={() => handleSaveComment()} className="btn btn-primary">
                            <i className="fas fa-pencil-alt"></i> Share
                        </button>
                    </div>
                </div>
                {inputValues.imageReview && (
                    <div
                        style={{ backgroundImage: `url(${inputValues.imageReview})` }}
                        className="preview-cmt-img"
                    ></div>
                )}
            </div>
        );
    };

    return (
        <div className="row">
            <div className="col-lg-12">
                {/* Tổng điểm đánh giá */}
                <div className="row total_rate">
                    <div className="col-6">
                        <div className="box_total">
                            <h5>Sao trung bình</h5>
                            <h4>
                                {inputValues.countStar.average
                                    ? Math.round(inputValues.countStar.average * 10) / 10
                                    : 0}
                            </h4>
                            <h6>({inputValues.countStar.quantity} lượt đánh giá)</h6>
                        </div>
                    </div>
                    <div className="col-6">
                        <div className="rating_list">
                            <h3>{inputValues.countStar.quantity} lượt đánh giá</h3>
                            <ul className="list">
                                <li>
                                    <a href="#">5
                                        <i className="fa fa-star" /><i className="fa fa-star" /><i className="fa fa-star" /><i className="fa fa-star" /><i className="fa fa-star" />
                                        Có {inputValues.countStar.star5} lượt đánh giá
                                    </a>
                                </li>
                                <li>
                                    <a href="#">4
                                        <i className="fa fa-star" /><i className="fa fa-star" /><i className="fa fa-star" /><i className="fa fa-star" />
                                        Có {inputValues.countStar.star4} lượt đánh giá
                                    </a>
                                </li>
                                <li>
                                    <a href="#">3
                                        <i className="fa fa-star" /><i className="fa fa-star" /><i className="fa fa-star" />
                                        Có {inputValues.countStar.star3} lượt đánh giá
                                    </a>
                                </li>
                                <li>
                                    <a href="#">2
                                        <i className="fa fa-star" /><i className="fa fa-star" />
                                        Có {inputValues.countStar.star2} lượt đánh giá
                                    </a>
                                </li>
                                <li>
                                    <a href="#">1
                                        <i className="fa fa-star" />
                                        Có {inputValues.countStar.star1} lượt đánh giá
                                    </a>
                                </li>
                            </ul>
                        </div>
                    </div>
                </div>

                {/* Danh sách review + form đánh giá */}
                <div className="review_list">

                    {/* Form đánh giá — có kiểm tra điều kiện */}
                    {renderReviewForm()}

                    {/* Danh sách review */}
                    {inputValues.dataReview && inputValues.dataReview.length > 0 &&
                        inputValues.dataReview.map((item, index) => {
                            if (!item.parentId) {
                                let name = `${item.user.firstName ? item.user.firstName : ''} ${item.user.lastName}`;
                                let arrStar = [];
                                for (let i = 0; i < item.star; i++) {
                                    arrStar[i] = 1;
                                }
                                return (
                                    <div key={index} className="review_item">
                                        <div className="media">
                                            <div className="d-flex">
                                                <img className="img-avatar" src={item.user.image} alt="" />
                                            </div>
                                            <div className="media-body">
                                                <h4>{name}</h4>
                                                {arrStar && arrStar.length > 0 &&
                                                    arrStar.map((star, idx) => (
                                                        <i key={idx} className="fa fa-star" />
                                                    ))
                                                }
                                                {user && user.roleId === 'R1' &&
                                                    <a
                                                        style={{ cursor: 'pointer' }}
                                                        onClick={() => handleOpenModal(item.id)}
                                                        className="reply_btn"
                                                    >
                                                        Phản hồi
                                                    </a>
                                                }
                                            </div>
                                        </div>
                                        <div style={{ marginLeft: '88px' }}>
                                            <p style={{ paddingTop: '0px' }}>{item.content}</p>
                                            {item.image &&
                                                <img
                                                    onClick={() => openPreviewImage(item.image)}
                                                    className="img-cmt"
                                                    src={item.image}
                                                    alt=""
                                                />
                                            }
                                            {item.childComment && item.childComment.length > 0 &&
                                                item.childComment.map((child, idx) => (
                                                    <div key={idx} className="box-reply">
                                                        <span>Phản hồi của người bán</span>
                                                        <p>{child.content}</p>
                                                        {user && user.roleId === 'R1' &&
                                                            <button
                                                                onClick={() => handleDeleteReply(child.id)}
                                                                className="btn-delete-reply"
                                                                type="button"
                                                            >
                                                                Xóa
                                                            </button>
                                                        }
                                                    </div>
                                                ))
                                            }
                                        </div>
                                    </div>
                                );
                            }
                            return null;
                        })
                    }
                </div>
            </div>

            {/* Lightbox xem ảnh */}
            {inputValues.isOpen === true &&
                <Lightbox
                    mainSrc={inputValues.imageReview}
                    onCloseRequest={() => setInputValues({
                        ...inputValues,
                        isOpen: false,
                        imageReview: ''
                    })}
                />
            }

            {/* Modal phản hồi (admin) */}
            <ReviewModal
                isOpenModal={inputValues.isOpenModal}
                closeModal={closeModal}
                sendDataFromReViewModal={sendDataFromReViewModal}
            />
        </div>
    );
}

export default ReviewProduct;
